# FILE: OneMoreTaskTracker.Features/Protos/UpdateFeatureCommand/update_feature_command_handler.proto
syntax = "proto3";
import "feature_state.proto";
import "feature_stage_plan.proto";

option csharp_namespace = "OneMoreTaskTracker.Proto.Features.UpdateFeatureCommand";
package mr_helper.features;

service FeatureUpdater {
  rpc Update (UpdateFeatureRequest) returns (FeatureDto);
}

message UpdateFeatureRequest {
  int32        id              = 1;
  string       title           = 2;
  string       description     = 3;
  FeatureState state           = 4;
  string       planned_start   = 5;
  string       planned_end     = 6;
  int32        lead_user_id    = 7;
  // Empty repeated = "do not touch stage plans" (partial update).
  // Non-empty = exactly 5 entries, one per FeatureState ordinal; upserted atomically.
  repeated     FeatureStagePlan stage_plans = 8;
  // Authenticated caller's user id (propagated from the gateway JWT).
  // Required at the service boundary so the Features service can re-verify
  // that the caller owns the target feature (`feature.ManagerUserId`).
  // 0 is an invalid value and yields PermissionDenied.
  // Double-defense per ~/.claude/rules/microservices/security.md.
  int32        caller_user_id  = 9;
}

message FeatureDto {
  int32        id                 = 1;
  string       title              = 2;
  string       description        = 3;
  FeatureState state              = 4;
  string       planned_start      = 5;
  string       planned_end        = 6;
  int32        lead_user_id       = 7;
  int32        manager_user_id    = 8;
  string       created_at         = 9;
  string       updated_at         = 10;
  repeated     FeatureStagePlan stage_plans = 11;
  // Monotonically-increasing row version used for optimistic concurrency.
  // Bumped by every feature- and stage-scoped PATCH (see api-contract.md
  // § "Optimistic Concurrency"). Additive — legacy clients ignore this field.
  int32        version            = 12;
}
