# FILE: OneMoreTaskTracker.Features/Protos/UpdateFeatureTitleCommand/update_feature_title_command_handler.proto
syntax = "proto3";
import "feature_state.proto";
import "feature_stage_plan.proto";

option csharp_namespace = "OneMoreTaskTracker.Proto.Features.UpdateFeatureTitleCommand";
package mr_helper.features;

// Narrow per-field PATCH surface for the Gantt inline-edit feature.
// The feature-scoped ownership guard and Feature.Version optimistic-concurrency
// token are enforced in UpdateFeatureTitleHandler (see backend-plan.md).
service FeatureTitleUpdater {
  rpc Update (UpdateFeatureTitleRequest) returns (FeatureDto);
}

message UpdateFeatureTitleRequest {
  int32  id               = 1;
  string title            = 2;
  // Authenticated caller's user id propagated from the gateway JWT. The
  // Features service re-verifies feature ownership via this field regardless
  // of what the gateway's [Authorize] enforces. Double-defense per
  // ~/.claude/rules/microservices/security.md.
  int32  caller_user_id   = 3;
  // Client's If-Match version. `optional` so the wire can distinguish
  // "no header sent" (advisory mode) from `If-Match: 0` (legitimate v=0
  // freshly-created feature). When present and the stored Feature.Version
  // differs, the handler throws RpcException(AlreadyExists) → HTTP 409.
  // When absent: advisory / last-write-wins.
  optional int32 expected_version = 4;
}

// Duplicated per-command so each proto file is independently routable by
// Mapster (see FeatureMappingConfig). Kept in lockstep with UpdateFeatureCommand.FeatureDto.
message FeatureDto {
  int32        id                 = 1;
  string       title              = 2;
  string       description        = 3;
  FeatureState state              = 4;
  string       planned_start      = 5;
  string       planned_end        = 6;
  int32        lead_user_id       = 7;
  int32        manager_user_id    = 8;
  string       created_at         = 9;
  string       updated_at         = 10;
  repeated     FeatureStagePlan stage_plans = 11;
  int32        version            = 12;
}
