  // Stage-scoped optimistic-concurrency token (FeatureStagePlan.Version).
  // `optional` so the wire can distinguish missing-header (advisory mode)
  // from `If-Match: 0`. Absent → last-write-wins; present + mismatch → 409.
  optional int32 expected_stage_version = 5;
}

